function ContactPage() {
  const [form, setForm] = useState({ name: "", email: "", company: "", message: "" });
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (field) => (e) => setForm({ ...form, [field]: e.target.value });

  const handleSubmit = () => {
    if (!form.name || !form.email || !form.message) return;
    setSubmitted(true);
  };

  const canSubmit = form.name && form.email && form.message;

  return (
    <section style={styles.section}>
      <div style={styles.container}>
        <FadeIn delay={100}>
          <h1 style={styles.pageTitle}>Contact Us</h1>
          <p style={styles.bodyText}>
            Ready to learn what your competitors are doing? Send us a brief description of
            your market and what you need to know. We will follow up to scope the engagement.
          </p>
        </FadeIn>

        <FadeIn delay={250}>
          {submitted ? (
            <div style={styles.card}>
              <h2 style={styles.cardTitle}>Thank you.</h2>
              <p style={styles.bodyText}>
                Your inquiry has been received. We will be in touch soon to discuss your needs.
              </p>
            </div>
          ) : (
            <div style={styles.card}>
              <div style={styles.formGroup}>
                <label style={styles.label}>Name *</label>
                <input
                  type="text"
                  value={form.name}
                  onChange={handleChange("name")}
                  style={styles.input}
                  placeholder="Your name"
                  onFocus={(e) => { e.target.style.borderColor = palette.accent; e.target.style.boxShadow = `0 0 0 2px ${palette.accentSubtle}`; }}
                  onBlur={(e) => { e.target.style.borderColor = palette.border; e.target.style.boxShadow = "none"; }}
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Email *</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={handleChange("email")}
                  style={styles.input}
                  placeholder="you@company.com"
                  onFocus={(e) => { e.target.style.borderColor = palette.accent; e.target.style.boxShadow = `0 0 0 2px ${palette.accentSubtle}`; }}
                  onBlur={(e) => { e.target.style.borderColor = palette.border; e.target.style.boxShadow = "none"; }}
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Company</label>
                <input
                  type="text"
                  value={form.company}
                  onChange={handleChange("company")}
                  style={styles.input}
                  placeholder="Your company (optional)"
                  onFocus={(e) => { e.target.style.borderColor = palette.accent; e.target.style.boxShadow = `0 0 0 2px ${palette.accentSubtle}`; }}
                  onBlur={(e) => { e.target.style.borderColor = palette.border; e.target.style.boxShadow = "none"; }}
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>What do you need to know? *</label>
                <textarea
                  value={form.message}
                  onChange={handleChange("message")}
                  style={{ ...styles.input, minHeight: "120px", resize: "vertical" }}
                  placeholder="Briefly describe your market, the competitors you are watching, and what decisions this research would inform."
                  onFocus={(e) => { e.target.style.borderColor = palette.accent; e.target.style.boxShadow = `0 0 0 2px ${palette.accentSubtle}`; }}
                  onBlur={(e) => { e.target.style.borderColor = palette.border; e.target.style.boxShadow = "none"; }}
                />
              </div>
              <button
                style={{
                  ...styles.btnPrimary,
                  opacity: canSubmit ? 1 : 0.4,
                  cursor: canSubmit ? "pointer" : "default",
                }}
                onClick={handleSubmit}
                onMouseEnter={(e) => { if (canSubmit) { e.target.style.background = palette.accentDim; e.target.style.boxShadow = `0 0 24px ${palette.accentGlow}`; } }}
                onMouseLeave={(e) => { e.target.style.background = palette.accent; e.target.style.boxShadow = `0 0 16px ${palette.accentGlow}`; }}
              >
                Send Inquiry
              </button>
              <p style={{ ...styles.bodyText, fontSize: "0.82rem", marginTop: "1rem", opacity: 0.5 }}>
                By submitting this form you agree to our Privacy Policy.
              </p>
            </div>
          )}
        </FadeIn>

        <FadeIn delay={400}>
          <div style={{ marginTop: "2.5rem" }}>
            <p style={styles.bodyText}>
              You can also reach us directly at{" "}
              <a href={`mailto:${BRAND.contactEmail}`} style={styles.link}>
                {BRAND.contactEmail}
              </a>
            </p>
            <p style={styles.bodyText}>
              Phone:{" "}
              <a href="tel:+13025488630" style={styles.link}>
                (302) 548-8630
              </a>
            </p>
          </div>
        </FadeIn>
      </div>
    </section>
  );
}

