// ─── Layout ───

function Header({ currentPage, navigate }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // Detail, step, FullServices, and FullProcess pages should highlight "Services" in nav
  const activeNav = (currentPage.startsWith("detail:") || currentPage.startsWith("step:") || currentPage === "FullServices" || currentPage === "FullProcess") ? "Services" : currentPage;

  return (
    <header style={{
      ...styles.header,
      boxShadow: scrolled ? `0 2px 20px rgba(0,0,0,0.4)` : "none",
      borderBottom: scrolled ? `1px solid ${palette.border}` : `1px solid transparent`,
    }}>
      <div style={styles.headerInner}>
        <div
          style={styles.logo}
          onClick={() => navigate("Home")}
          role="button"
          tabIndex={0}
        >
          <img src={ES_LOGO} alt="EchoStack Media" style={styles.logoImg} />
        </div>

        {/* Desktop nav */}
        <nav style={styles.desktopNav}>
          {NAV_PAGES.map((p) => (
            <button
              key={p}
              onClick={() => navigate(p)}
              style={{
                ...styles.navLink,
                ...(activeNav === p ? styles.navLinkActive : {}),
              }}
              onMouseEnter={(e) => { if (activeNav !== p) e.target.style.color = palette.white; }}
              onMouseLeave={(e) => { if (activeNav !== p) e.target.style.color = palette.textMuted; }}
            >
              {p}
            </button>
          ))}
        </nav>

        {/* Mobile toggle */}
        <button
          style={styles.mobileToggle}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle navigation"
        >
          {menuOpen ? "\u2715" : "\u2630"}
        </button>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div style={styles.mobileMenu}>
          {NAV_PAGES.map((p) => (
            <button
              key={p}
              onClick={() => { navigate(p); setMenuOpen(false); }}
              style={{
                ...styles.mobileNavLink,
                ...(activeNav === p ? styles.navLinkActive : {}),
              }}
            >
              {p}
            </button>
          ))}
        </div>
      )}
    </header>
  );
}

